/**
 * Measures intra-query morsel parallelism on scan- and aggregation-heavy COUNT and exact decimal queries, alongside
 * floating SUM/AVG variants that must fall back to sequential encounter order. Run twice — once as-is and once with
 * {@code -Drdf4j.lmdb.parallel.enabled=false} — to compare against the single-threaded engine. Trial setup verifies
 * both results and the expected parallel-or-fallback strategy.
 */
@State(Scope.Benchmark)
@Warmup(iterations = 4, time = 2, timeUnit = TimeUnit.SECONDS)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 3, jvmArgs = { "-Xms1G", "-Xmx4G" })
@Measurement(iterations = 4, batchSize = 1, time = 2, timeUnit = TimeUnit.SECONDS)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
public class ParallelAggregationBenchmark {

	private static final String EX = "http://example.com/";
	private static final int HUBS = 10_000;
	private static final int P1_FANOUT = 10;
	private static final int P2_FANOUT = 20;
	private static final int P2_DISTINCT_VALUES = 5_000;
	private static final String PARALLEL_FLAG = "rdf4j.lmdb.parallel.enabled";
	private static final String PARALLEL_THRESHOLD_FLAG = "rdf4j.lmdb.parallel.minRootEstimate";

	@Param({
			"countHub",
			"countDistinctTail",
			"groupByHub",
			"sumDecimal",
			"avgDecimal",
			"sumDoubleFallback",
			"avgDoubleFallback",
			"sumFloatFallback",
			"avgFloatFallback"
	})
	public String variant;

	private java.io.File dataDir;
	private SailRepository repository;
	private String query;
	private long expected;
	private BigDecimal expectedDecimal;
	private double expectedDouble;
	private float expectedFloat;
	private String expectedStrategy;

	@Setup(Level.Trial)
	public void setUp() {
		System.setProperty(PARALLEL_THRESHOLD_FLAG, "0");
		expected = 0L;
		expectedDecimal = null;
		expectedDouble = 0D;
		expectedFloat = 0F;
		expectedStrategy = Boolean.parseBoolean(System.getProperty(PARALLEL_FLAG, "true"))
				? "parallelAggregation"
				: null;
		dataDir = Files.newTemporaryFolder();
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			IRI decimal = vf.createIRI(EX, "decimal");
			IRI floating = vf.createIRI(EX, "floating");
			conn.begin();
			for (int hub = 0; hub < HUBS; hub++) {
				IRI subject = vf.createIRI(EX, "hub" + hub);
				if (variant.endsWith("Decimal")) {
					conn.add(subject, decimal, vf.createLiteral(BigDecimal.valueOf(hub, 2)));
				} else if (variant.endsWith("DoubleFallback")) {
					conn.add(subject, floating, vf.createLiteral(0.1D));
				} else if (variant.endsWith("FloatFallback")) {
					conn.add(subject, floating, vf.createLiteral(0.1F));
				}
				for (int i = 0; i < P1_FANOUT; i++) {
					conn.add(subject, p1, vf.createIRI(EX, "a" + (hub * P1_FANOUT + i)));
				}
				for (int i = 0; i < P2_FANOUT; i++) {
					conn.add(subject, p2, vf.createIRI(EX, "b" + ((hub * P2_FANOUT + i) % P2_DISTINCT_VALUES)));
				}
			}
			conn.commit();
		}
		long solutions = (long) HUBS * P1_FANOUT * P2_FANOUT;
		switch (variant) {
		case "countHub":
			query = star("(COUNT(?s) AS ?count)");
			expected = solutions;
			break;
		case "countDistinctTail":
			query = star("(COUNT(DISTINCT ?b) AS ?count)");
			expected = P2_DISTINCT_VALUES;
			break;
		case "groupByHub":
			query = star("?s (COUNT(?b) AS ?count)") + " GROUP BY ?s";
			expected = (long) P1_FANOUT * P2_FANOUT;
			break;
		case "sumDecimal":
			query = numeric("SUM", "decimal");
			expectedDecimal = BigDecimal.valueOf((long) HUBS * (HUBS - 1) / 2, 2)
					.multiply(BigDecimal.valueOf((long) P1_FANOUT * P2_FANOUT));
			break;
		case "avgDecimal":
			query = numeric("AVG", "decimal");
			expectedDecimal = BigDecimal.valueOf(HUBS - 1L, 2).divide(BigDecimal.valueOf(2));
			break;
		case "sumDoubleFallback":
			query = numeric("SUM", "floating");
			expectedDouble = repeatedDoubleSum(solutions, 0.1D);
			expectedStrategy = "aggState";
			break;
		case "avgDoubleFallback":
			query = numeric("AVG", "floating");
			expectedDouble = repeatedDoubleSum(solutions, 0.1D) / solutions;
			expectedStrategy = "aggState";
			break;
		case "sumFloatFallback":
			query = numeric("SUM", "floating");
			expectedFloat = repeatedFloatSum(solutions, 0.1F);
			expectedStrategy = "aggState";
			break;
		case "avgFloatFallback":
			query = numeric("AVG", "floating");
			expectedFloat = repeatedFloatSum(solutions, 0.1F) / solutions;
			expectedStrategy = "aggState";
			break;
		default:
			throw new IllegalArgumentException(variant);
		}
		executeQuery();
		String actualStrategy = strategy();
		if (expectedStrategy != null && !expectedStrategy.equals(actualStrategy)) {
			throw new IllegalStateException(
					variant + ": expected strategy " + expectedStrategy + " but got " + actualStrategy);
		}
		if (expectedStrategy == null && "parallelAggregation".equals(actualStrategy)) {
			throw new IllegalStateException(variant + ": disabled control unexpectedly used parallel aggregation");
		}
	}

	private static String star(String select) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "}";
	}

	private static String numeric(String aggregate, String predicate) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT (" + aggregate + "(?n) AS ?value) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "  ?s ex:" + predicate + " ?n .\n"
				+ "}";
	}

	private static double repeatedDoubleSum(long count, double value) {
		double sum = 0D;
		for (long i = 0; i < count; i++) {
			sum += value;
		}
		return sum;
	}

	private static float repeatedFloatSum(long count, float value) {
		float sum = 0F;
		for (long i = 0; i < count; i++) {
			sum += value;
		}
		return sum;
	}

	@TearDown(Level.Trial)
	public void tearDown() throws IOException {
		try {
			repository.shutDown();
			FileUtil.deleteDir(dataDir);
		} finally {
			System.clearProperty(PARALLEL_THRESHOLD_FLAG);
		}
	}

	private String strategy() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			GenericPlanNode plan = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Telemetry)
					.toGenericPlanNode();
			String strategy = findStrategy(plan);
			if (strategy == null) {
				throw new IllegalStateException(variant + ": explanation did not report nativeExecutionStrategy");
			}
			return strategy;
		}
	}

	private static String findStrategy(GenericPlanNode node) {
		if (node == null) {
			return null;
		}
		String strategy = node.getStringMetricActual("nativeExecutionStrategy");
		if (strategy != null) {
			return strategy;
		}
		if (node.getPlans() != null) {
			for (GenericPlanNode child : node.getPlans()) {
				String found = findStrategy(child);
				if (found != null) {
					return found;
				}
			}
		}
		return null;
	}

	@Benchmark
	public long executeQuery() {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			if (expectedDecimal != null || variant.endsWith("Fallback")) {
				if (result.size() != 1) {
					throw new IllegalStateException(variant + ": expected one aggregate row but got " + result.size());
				}
				Literal value = (Literal) result.get(0).getValue("value");
				if (expectedDecimal != null) {
					if (value.decimalValue().compareTo(expectedDecimal) != 0) {
						throw new IllegalStateException(
								variant + ": expected " + expectedDecimal + " but got " + value);
					}
					return value.decimalValue().longValue();
				}
				if (variant.endsWith("FloatFallback")) {
					float actual = value.floatValue();
					if (Float.floatToIntBits(actual) != Float.floatToIntBits(expectedFloat)) {
						throw new IllegalStateException(variant + ": expected " + expectedFloat + " but got " + actual);
					}
					return Float.floatToIntBits(actual);
				}
				double actual = value.doubleValue();
				if (Double.doubleToLongBits(actual) != Double.doubleToLongBits(expectedDouble)) {
					throw new IllegalStateException(variant + ": expected " + expectedDouble + " but got " + actual);
				}
				return Double.doubleToLongBits(actual);
			}
			long total = 0;
			for (BindingSet bindings : result) {
				long count = ((Literal) bindings.getValue("count")).longValue();
				if (count != expected) {
					throw new IllegalStateException(variant + ": expected " + expected + " but got " + count);
				}
				total += count;
			}
			if ("groupByHub".equals(variant) && result.size() != HUBS) {
				throw new IllegalStateException("groupByHub: expected " + HUBS + " groups but got " + result.size());
			}
			return total;
		}
	}

	public static void main(String[] args) throws RunnerException {
		Options opt = new OptionsBuilder()
				.include("ParallelAggregationBenchmark")
				.build();
		new Runner(opt).run();
	}
}
